const services = [
  { name: 'API Backend',     url: 'http://api:8000/status',       container: 'hermes_api' },
  { name: 'Telegram Bot',   url: 'http://telegram-bot:3003/health', container: 'hermes_telegram_bot' },
  { name: 'WhatsApp',       url: 'http://wa:3001/status',          container: 'hermes_wa' },
  { name: 'Frontend',       url: 'http://frontend:3000',           container: 'hermes_frontend' },
  { name: 'N8N',            url: 'http://n8n:5678/healthz',        container: 'hermes_n8n' }
];

const results = [];
for (const svc of services) {
  try {
    const res = await $http.get({ url: svc.url, timeout: 5000 });
    results.push({ ...svc, status: 'ok', code: res.statusCode });
  } catch (e) {
    results.push({ ...svc, status: 'down', error: e.message.substring(0, 100) });
  }
}

const failed = results.filter(r => r.status === 'down');
const ok = results.filter(r => r.status === 'ok');

return [{
  json: {
    timestamp: new Date().toISOString(),
    total: services.length,
    ok: ok.length,
    failed: failed.length,
    services: results,
    failedServices: failed,
    allOk: failed.length === 0
  }
}];

