// Intenta reiniciar cada servicio caído via Docker REST API
// Requiere: docker run -d -v /var/run/docker.sock:/var/run/docker.sock -p 2375:2375 bobrik/socat TCP-LISTEN:2375,fork UNIX-CONNECT:/var/run/docker.sock
const failed = $json.failedServices || [];
const restarted = [];
const dockerApi = $env.DOCKER_API_URL || 'http://host.docker.internal:2375';

for (const svc of failed) {
  if (!svc.container) continue;
  try {
    await $http.post({
      url: `${dockerApi}/containers/${svc.container}/restart`,
      headers: { 'Content-Type': 'application/json' }
    });
    restarted.push(svc.name);
    await new Promise(r => setTimeout(r, 3000)); // espera 3s entre reinicios
  } catch (e) {
    restarted.push(`${svc.name} (restart fallido: ${e.message.substring(0,50)})`);
  }
}

return [{ json: { restarted, failedServices: failed, timestamp: new Date().toISOString() } }];

const prevFailed = $('Reiniciar contenedores caídos').first().json.failedServices || [];
const restarted = $('Reiniciar contenedores caídos').first().json.restarted || [];
const recovered = [];
const stillDown = [];

for (const svc of prevFailed) {
  try {
    const res = await $http.get({ url: svc.url, timeout: 8000 });
    recovered.push(svc.name);
  } catch (e) {
    stillDown.push({ ...svc, error: e.message.substring(0,100) });
  }
}

return [{ json: { recovered, stillDown, restarted, timestamp: new Date().toISOString() } }];

